compliant:
char buffer[10];
char *src = "This is a long string that will overflow";
strncpy(buffer, src, sizeof(buffer) - 1);
buffer[sizeof(buffer) - 1] = '\0'; // Compliant: bounded copy

int arr[5];
for (int i = 0; i < 5; i++) {
    arr[i] = i; // Compliant: proper bounds checking
}
